import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import VirtualKeyboard from '../components/VirtualKeyboard';
import './Lesson.css';

const Lesson = () => {
  const { chapterId, lessonId } = useParams();
  const navigate = useNavigate();

  const [lessonData, setLessonData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Typing state
  const [userInput, setUserInput] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [errors, setErrors] = useState(0);
  const [wrongChar, setWrongChar] = useState(false); // tracks if current char is wrong
  const [startTime, setStartTime] = useState(null);
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [isComplete, setIsComplete] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [lastKeyCorrect, setLastKeyCorrect] = useState(null);
  const soundTimeoutRef = useRef(null);

  const inputRef = useRef(null);
  const timerRef = useRef(null);

  useEffect(() => {
    fetchLesson();
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [chapterId, lessonId]);

  useEffect(() => {
    if (inputRef.current && !isComplete) {
      inputRef.current.focus();
    }
  }, [isComplete]);

  const fetchLesson = async () => {
    try {
      const response = await chaptersAPI.getLesson(chapterId, lessonId);
      setLessonData(response.data);
    } catch (err) {
      console.error('Error fetching lesson:', err);
      setError('Failed to load lesson');
    } finally {
      setLoading(false);
    }
  };

  const startTimer = () => {
    if (!startTime) {
      setStartTime(Date.now());
      timerRef.current = setInterval(() => {
        setTimeElapsed((Date.now() - Date.now()) / 1000);
      }, 100);
    }
  };

  const calculateStats = () => {
    const content = lessonData.lesson.content;
    const timeInMinutes = timeElapsed / 60 || 0.1;
    const wordsTyped = userInput.trim().split(/\s+/).length;
    const wpm = Math.round(wordsTyped / timeInMinutes);
    const accuracy = Math.max(0, Math.round(((content.length - errors) / content.length) * 100));

    return { wpm, accuracy, timeElapsed: Math.round(timeElapsed) };
  };

  const handleSubmit = async () => {
    if (timerRef.current) {
      clearInterval(timerRef.current);
    }

    const actualTimeElapsed = startTime ? (Date.now() - startTime) / 1000 : 0;
    setTimeElapsed(actualTimeElapsed);

    const stats = calculateStats();

    try {
      await progressAPI.submitLesson({
        chapterId,
        lessonId,
        wpm: stats.wpm,
        accuracy: stats.accuracy
      });

      setIsComplete(true);
      setShowResults(true);
    } catch (err) {
      console.error('Error submitting progress:', err);
      alert('Failed to save progress. Please try again.');
    }
  };

  const handleInputChange = (e) => {
    const value = e.target.value;
    const content = lessonData.lesson.content;

    if (!startTime) {
      startTimer();
    }

    const lessonType = lessonData.lesson.lessonType;

    if (lessonType === 'intro' || lessonType === 'random-words' || lessonType === 'meaningful-words') {
      const currentChar = content[currentIndex];
      const typedChar = value[value.length - 1];

      if (value.length > userInput.length) {
        if (typedChar !== currentChar) {
          // Wrong key - show red on current char, play wrong sound, don't advance
          setErrors(errors + 1);
          setWrongChar(true);
          setLastKeyCorrect(false);
          return;
        } else {
          // Correct key - clear red, play correct sound, advance
          setWrongChar(false);
          setLastKeyCorrect(true);
          setUserInput(value);
          setCurrentIndex(currentIndex + 1);
          if (currentIndex + 1 >= content.length) {
            handleSubmit();
          }
        }
      } else {
        // Backspace
        setWrongChar(false);
        setUserInput(value);
        setCurrentIndex(Math.max(0, currentIndex - 1));
      }
    } else if (lessonType === 'sentences') {
      setUserInput(value);
    } else if (lessonType === 'paragraph') {
      if (value.length > userInput.length) {
        const typedChar = value[value.length - 1];
        const currentChar = content[currentIndex];
        if (typedChar === currentChar) {
          setLastKeyCorrect(true);
          setWrongChar(false);
          setCurrentIndex(currentIndex + 1);
        } else {
          setLastKeyCorrect(false);
          setWrongChar(true);
          setErrors(errors + 1);
          setCurrentIndex(currentIndex + 1);
        }
      }
      setUserInput(value);
    }
  };

  const handleKeyDown = (e) => {
    const lessonType = lessonData?.lesson?.lessonType;

    if (lessonType === 'sentences' && e.key === 'Enter') {
      e.preventDefault();
      // Check sentence accuracy
      const currentSentence = userInput.trim();
      const sentences = lessonData.lesson.content.split('. ');
      const currentSentenceIndex = Math.floor(currentIndex / (lessonData.lesson.content.length / sentences.length));

      if (currentSentence !== sentences[currentSentenceIndex]) {
        const errorCount = Math.abs(currentSentence.length - sentences[currentSentenceIndex].length);
        setErrors(errors + errorCount);
      }

      setCurrentIndex(currentIndex + currentSentence.length + 2); // +2 for '. '
      setUserInput('');

      if (currentSentenceIndex + 1 >= sentences.length) {
        handleSubmit();
      }
    }
  };

  const renderContent = () => {
    const content = lessonData.lesson.content;
    const lessonType = lessonData.lesson.lessonType;

    if (lessonType === 'paragraph') {
      return <div>{content}</div>;
    }

    return content.split('').map((char, index) => {
      let className = '';

      if (index < currentIndex) {
        className = 'correct';
      } else if (index === currentIndex) {
        className = wrongChar ? 'incorrect' : 'current';
      }

      return (
        <span key={index} className={className}>
          {char}
        </span>
      );
    });
  };

  const getCurrentKey = () => {
    if (!lessonData || isComplete) return null;
    const content = lessonData.lesson.content;
    return content[currentIndex];
  };

  if (loading) {
    return <div className="loading">Loading lesson...</div>;
  }

  if (error || !lessonData) {
    return (
      <div className="container">
        <div className="error">{error || 'Lesson not found'}</div>
        <button className="btn btn-primary" onClick={() => navigate('/learn')}>
          Back to Lessons
        </button>
      </div>
    );
  }

  const { chapter, lesson } = lessonData;
  const showKeyboard = lesson.lessonType !== 'paragraph';
  const stats = showResults ? calculateStats() : null;

  return (
    <div className="lesson-container-with-panel">
      <div className="lesson-main-area">
        {/* Compact Header - Single Line */}
        <div className="lesson-header-compact">
          <h3>Chapter {chapter.chapterNumber} • Lesson {lesson.lessonNumber}</h3>
          <span className="header-divider">|</span>
          <p>{lesson.lessonTitle}</p>
        </div>

        {/* Typing Content */}
        <div className="typing-content">
          {renderContent()}
        </div>

        {/* Typing Input */}
        {!isComplete && (
          <textarea
            ref={inputRef}
            className="typing-input"
            value={userInput}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder={
              lesson.lessonType === 'sentences'
                ? 'Type the sentence and press Enter...'
                : 'Start typing...'
            }
            autoFocus
          />
        )}

        {/* Virtual Keyboard */}
        {showKeyboard && !isComplete && (
          <VirtualKeyboard activeKey={getCurrentKey()} isCorrect={lastKeyCorrect} />
        )}
      </div>

      {/* Right Side Control Panel */}
      {!isComplete && (
        <div className="control-panel-right">
          <div className="control-stat">
            <div className="stat-label">⏱️ TIMER</div>
            <div className="stat-value-large timer-color">{Math.round(timeElapsed)}s</div>
          </div>

          <div className="control-stat">
            <div className="stat-label">✓ ACCURACY</div>
            <div className="stat-value-large accuracy-color">
              {currentIndex > 0
                ? Math.round(((currentIndex - errors) / currentIndex) * 100)
                : 100}
              %
            </div>
          </div>

          <div className="control-stat">
            <div className="stat-label">❌ ERRORS</div>
            <div className="stat-value-large error-color">{errors}</div>
          </div>

          <div className="control-stat">
            <div className="stat-label">⚡ WPM</div>
            <div className="stat-value-large wpm-color">
              {timeElapsed > 0
                ? Math.round(
                    (userInput.trim().split(/\s+/).length / timeElapsed) * 60
                  )
                : 0}
            </div>
          </div>

          <div className="control-buttons">
            <button className="btn-control btn-submit" onClick={handleSubmit}>
              Submit
            </button>
            <button
              className="btn-control btn-exit"
              onClick={() => navigate('/learn')}
            >
              Exit
            </button>
          </div>
        </div>
      )}

      {/* Results Modal */}
      {showResults && stats && (
        <div className="results-modal">
          <div className="results-content">
            <h2>Lesson Complete! 🎉</h2>
            <div className="results-stats">
              <div className="result-stat">
                <h3>{stats.wpm}</h3>
                <p>Words Per Minute</p>
              </div>
              <div className="result-stat">
                <h3>{stats.accuracy}%</h3>
                <p>Accuracy</p>
              </div>
              <div className="result-stat">
                <h3>{stats.timeElapsed}s</h3>
                <p>Time Taken</p>
              </div>
              <div className="result-stat">
                <h3>{errors}</h3>
                <p>Errors</p>
              </div>
            </div>
            <div className="results-actions">
              <button className="btn btn-primary" onClick={() => navigate('/learn')}>
                Back to Lessons
              </button>
              <button
                className="btn btn-secondary"
                onClick={() => window.location.reload()}
              >
                Try Again
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Lesson;
